# workflow_canvas.py — Claude Code output
FIELDS = ['workstream','surface','allowed_inputs',
          'forbidden_inputs','output_artifact',
          'constraints','human_gate','memory_scope',
          'failure_signal','improvement_note']
REQUIRED = {'forbidden_inputs','human_gate'}

def prompt_canvas():
    data = {}
    for field in FIELDS:
        val = input(f'{field}: ').strip()
        data[field] = val
    for req in REQUIRED:
        if not data.get(req):
            raise ValueError(
              f'REFUSED: {req} must not be blank')
    return data

